{
  "verses": [
    {
      "n": 18,
      "column": "left",
      "text": "Un Kaäta Behrni bija:\nAmrams/ un Jezeaṙs/ un Ee-\nbrons/ un Usiels.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Un tee Behrni Merara\nbija : Maëlus un Musus. Un\nfchee irr to Lewitu Raddi pehz\nwixnu Tehweem.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Gersona Dehls bija Lib-\nnus/ ta Dehls bija Jakats/ ta\nDehls bija Simus.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Ta Dehls bija Joaks/ ta\nDehls bija Jodns/ ta Dehls bija\nSeerus/ta Dehls bija Jeatrajus.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Kaäta Behrni bija: Am-\nminadabs/ ta Dehls bija Korus/\nta Dehls bija AAtirs.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Ta Dehls bija Elkanus/\nta Dehls bija Abi- Affaws / ta\nDehls bija Affrs.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Ta Dehls bija Tääts/ta\nDehls bija Uriels/ ta Dehls bija\nUsijus/ ta Dehls bija Sauls.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Un Elkanus Behrni bija:\nAmasajus un Akimots.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Ta Dehls bija Elkanus/\nta Dehls bija Elkanus no Zo-\nwags/ta Dehls bija Nääts.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Ta Dehls bija Elijabę/\nta Dehls bija Jeroams/ ta Dehls\nbija Elkanus.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Un Samueta Behrni bi-\nja: Tas pirmdsintajs Wasaus\nun Abtjus.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Merara Behrni bija:\nMaėlus/ ta Dehls bija Libmus/\nta Dehls bija Sinejus/ ta Dehls\nbtja Usus.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Ta Dehls bija Simėns/\nta Dehls bija Aggijus/ ta Dehls\nbtja Asajus.\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Un fchee irr tee / ko Dah-\nwidę eezeble par Dseedatajeem ta\nKUNGA Nammâ/ kur tas\nSchkirsts dusfeja.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Un tee kalpoja preefsch\ntahę Sa-eefchanas Telts Dsih-\nwokta ar Dseedatchanahm / tee-\nkams Salamans ta KUNGA\nNammu Jerusaleime nstaifija.\nUn tee stahweja pehz fawu Ge-\nraddumu eefsch fawas Kalpo-\nschanas.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Un fchee irr/ kas stahwe-\nja ar faweem Behrneem. No\nto Kaätiteru Behrneem Eemans\ntas Dseedatajs/ Joėta Dehls/ ta\nDehla Samueta.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Ta Dehla Elkanus / ta\nDehla Jeroama/ ta Dehta Eli-\neta/ ta Dehla Zous.\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Ta Dehla Zuwa/ ta Deh-\nla Elkanus/ ta Dehla Marita/ ta\nDehla Amasaja.\n"
    },
    {
      "n": 36,
      "column": "right",
      "text": "Ta Dehla Elkanus / ta\nDehla Joėta/ ta Dehla Asarijus/\nta Dehla Zewanjus.\n"
    },
    {
      "n": 37,
      "column": "right",
      "text": "Ta Dehla Takata / ta\nDehla Affira/ ta Dehla Abi-Af-\nfawa/ ta Dehla Korus.\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Ta Dehla Jezeara / ta\nDehla Kaäta/ ta Dehla Leivja/\nIsraėta Dehla.\n"
    },
    {
      "n": 39,
      "column": "right",
      "text": "Un winna Brahlts Affaws\nstahweja winnam va labbo Roh-\nfu/ Affaws btja Berekijus Dehls/\nta Dehla Sineüis.\n"
    },
    {
      "n": 40,
      "column": "right",
      "text": "Ta Dehla Mikaėta/ ta\nDehla Baėsejus/ ta Dehla Mat-\ntjus.\n"
    }
  ],
  "confidence": "high",
